CREATE TABLE student_grades (
    student_id  INTEGER       PRIMARY KEY,
    full_name   VARCHAR(120)  NOT NULL,
    score       DECIMAL(5,2)  NOT NULL CHECK (score BETWEEN 0 AND 100),
    grade_date  DATE          NOT NULL
);

INSERT INTO student_grades VALUES
    (1, 'Maya Patel',  88.50, '2024-05-15'),
    (2, 'James Chen',  74.00, '2024-05-15'),
    (3, 'Sofia Ruiz',  95.75, '2024-05-15');

-- Extract meaning from data: class average
SELECT ROUND(AVG(score), 2) AS class_average FROM student_grades;

-- Wrong: product_code stored as text even when it's always an integer
CREATE TABLE products_bad (
    product_code  VARCHAR(20),  -- '9' sorts after '10', arithmetic impossible
    price         VARCHAR(20)   -- Can store 'N/A', breaks SUM()
);

-- Right: numeric columns use numeric types
CREATE TABLE products_good (
    product_code  INTEGER        PRIMARY KEY,
    price         DECIMAL(10, 2) NOT NULL CHECK (price >= 0)
);

-- Wrong: comma-separated tags in a single VARCHAR column
INSERT INTO articles (id, tags) VALUES (1, 'sql,database,beginner');

-- Querying tags requires fragile LIKE patterns; indexes are useless
SELECT * FROM articles WHERE tags LIKE '%sql%';

-- Right: a separate tags table with a foreign key
CREATE TABLE article_tags (
    article_id  BIGINT      NOT NULL REFERENCES articles(id),
    tag         VARCHAR(50) NOT NULL,
    PRIMARY KEY (article_id, tag)
);

-- PostgreSQL: JSONB column with GIN index for flexible attributes
CREATE TABLE products (
    id          BIGINT  PRIMARY KEY GENERATED ALWAYS AS IDENTITY,
    name        VARCHAR(200) NOT NULL,
    price       DECIMAL(10, 2) NOT NULL CHECK (price >= 0),
    attributes  JSONB
);

CREATE INDEX idx_products_attributes ON products USING GIN (attributes);

-- Query: find products where color is 'red' (index-assisted)
SELECT id, name, price
FROM products
WHERE attributes @> '{"color": "red"}';

-- Always use parameterized queries — never interpolate user input into SQL
-- Python + psycopg2 example
cursor.execute(
    "SELECT id, name FROM employees WHERE department = %s AND active = %s",
    (department_input, True)   -- values passed separately, cannot be SQL
)

-- PostgreSQL RLS: restrict rows by the current application user
ALTER TABLE orders ENABLE ROW LEVEL SECURITY;

CREATE POLICY orders_own_rows ON orders
    USING (customer_id = current_setting('app.current_user_id')::BIGINT);
